use crate::pleromatic_frame::{
    NeurosymbolicToolMarkovMetrics, PleromaticFrame, NEUROSYMBOLIC_TOOL_MARKOV_FRAME_KIND,
};
use crate::semantic_authority_boundary::{
    compile_semantic_authority_boundary, SemanticAuthorityBoundaryReport,
    SemanticAuthorityClaimSpec,
};
use serde::{Deserialize, Serialize};

pub const NEUROSYMBOLIC_TOOL_MARKOV_THEOREM: &str =
    "Gnosis.NeurosymbolicToolUseMarkov.tool_use_markov_non_authority";

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub enum NeurosymbolicLayer {
    C0,
    C1,
    C2,
    C3,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum ToolUseMarkovState {
    ToolCandidate,
    ScoreCalibrated,
    SymbolicChecked,
    FrameworkAudited,
    SyntheticGnosisGain,
    ShadowResidual,
    UnresolvedRegression,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum ToolUseTransitionVerdict {
    SyntheticGnosisGain,
    ShadowExposed,
    Plateau,
    Regression,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum ToolUseNextAction {
    FoldIntoPrompt,
    ArgueObligations,
    RepairTooling,
}

impl ToolUseNextAction {
    pub fn as_attr(self) -> &'static str {
        match self {
            Self::FoldIntoPrompt => "foldIntoPrompt",
            Self::ArgueObligations => "argueObligations",
            Self::RepairTooling => "repairTooling",
        }
    }
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct C0C3GateReport {
    pub c0_tool_observation: bool,
    pub c1_score_calibration: bool,
    pub c2_symbolic_validation: bool,
    pub c3_framework_audit: bool,
}

impl C0C3GateReport {
    pub fn complete(&self) -> bool {
        self.c0_tool_observation
            && self.c1_score_calibration
            && self.c2_symbolic_validation
            && self.c3_framework_audit
    }
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ToolUseObservation {
    pub tool: String,
    #[serde(default)]
    pub layer: Option<NeurosymbolicLayer>,
    pub before_score: u64,
    pub after_score: u64,
    #[serde(default)]
    pub evidence_bytes: u64,
    #[serde(default)]
    pub residual_shadow: u64,
    #[serde(default)]
    pub symbolic_obligation_count: u32,
    #[serde(default = "default_symbolic_checks_passed")]
    pub symbolic_checks_passed: bool,
    #[serde(default)]
    pub output_checksum: Option<String>,
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ToolUseMarkovSpec {
    pub source_id: String,
    #[serde(default)]
    pub sequence: u64,
    #[serde(default)]
    pub initial_score: Option<u64>,
    #[serde(default)]
    pub final_score: Option<u64>,
    #[serde(default)]
    pub authority_claims: Vec<SemanticAuthorityClaimSpec>,
    pub steps: Vec<ToolUseObservation>,
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ToolUseMarkovTransition {
    pub index: usize,
    pub tool: String,
    pub layer: NeurosymbolicLayer,
    pub from_state: ToolUseMarkovState,
    pub to_state: ToolUseMarkovState,
    pub verdict: ToolUseTransitionVerdict,
    pub before_score: u64,
    pub after_score: u64,
    pub score_gain: u64,
    pub regression_debt: u64,
    pub observed_mass: u64,
    pub shadow_mass: u64,
    pub residual_shadow: u64,
    pub symbolic_obligation_count: u32,
    pub symbolic_checks_passed: bool,
    pub output_checksum: Option<String>,
    pub gate: C0C3GateReport,
    pub disciplined: bool,
}

#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct ToolUseMarkovReport {
    pub kind: String,
    pub theorem: String,
    pub source_id: String,
    pub sequence: u64,
    pub initial_score: u64,
    pub final_score: u64,
    pub transitions: Vec<ToolUseMarkovTransition>,
    pub authority_boundary: SemanticAuthorityBoundaryReport,
    pub metrics: NeurosymbolicToolMarkovMetrics,
    pub recommended_next_action: ToolUseNextAction,
    pub observational_only: bool,
}

pub fn compile_neurosymbolic_tool_markov_report(spec: ToolUseMarkovSpec) -> ToolUseMarkovReport {
    let transitions = spec
        .steps
        .iter()
        .enumerate()
        .map(|(index, step)| compile_transition(index, step))
        .collect::<Vec<_>>();
    let authority_boundary = compile_semantic_authority_boundary(spec.authority_claims);
    let metrics = compute_metrics(&transitions, &authority_boundary);
    let recommended_next_action = recommended_next_action(&metrics);
    let initial_score = spec.initial_score.unwrap_or_else(|| {
        spec.steps
            .first()
            .map(|step| step.before_score)
            .unwrap_or_default()
    });
    let final_score = spec.final_score.unwrap_or_else(|| {
        spec.steps
            .last()
            .map(|step| step.after_score)
            .unwrap_or(initial_score)
    });

    ToolUseMarkovReport {
        kind: NEUROSYMBOLIC_TOOL_MARKOV_FRAME_KIND.to_string(),
        theorem: NEUROSYMBOLIC_TOOL_MARKOV_THEOREM.to_string(),
        source_id: spec.source_id,
        sequence: spec.sequence,
        initial_score,
        final_score,
        transitions,
        authority_boundary,
        metrics,
        recommended_next_action,
        observational_only: true,
    }
}

pub fn tool_markov_report_to_frame(
    report: &ToolUseMarkovReport,
) -> Result<PleromaticFrame, serde_json::Error> {
    let payload = serde_json::to_vec(report)?;
    Ok(PleromaticFrame::neurosymbolic_tool_markov_consciousness(
        report.source_id.clone(),
        report.metrics.clone(),
        payload,
    ))
}

fn compile_transition(index: usize, step: &ToolUseObservation) -> ToolUseMarkovTransition {
    let score_gain = step.after_score.saturating_sub(step.before_score);
    let regression_debt = step.before_score.saturating_sub(step.after_score);
    let symbolic_shadow = if step.symbolic_checks_passed { 0 } else { 1 };
    let exposed_shadow = step
        .residual_shadow
        .saturating_add(step.symbolic_obligation_count as u64)
        .saturating_add(symbolic_shadow);
    let verdict = if score_gain > 0 {
        ToolUseTransitionVerdict::SyntheticGnosisGain
    } else if exposed_shadow > 0 {
        ToolUseTransitionVerdict::ShadowExposed
    } else if regression_debt > 0 {
        ToolUseTransitionVerdict::Regression
    } else {
        ToolUseTransitionVerdict::Plateau
    };
    let layer = step.layer.unwrap_or_else(|| inferred_layer(step, verdict));
    let gate = C0C3GateReport {
        c0_tool_observation: !step.tool.trim().is_empty()
            && (step.evidence_bytes > 0 || step.output_checksum.is_some()),
        c1_score_calibration: true,
        c2_symbolic_validation: step.symbolic_checks_passed && step.symbolic_obligation_count == 0,
        c3_framework_audit: matches!(
            verdict,
            ToolUseTransitionVerdict::SyntheticGnosisGain | ToolUseTransitionVerdict::ShadowExposed
        ),
    };
    let disciplined = score_gain > 0 || exposed_shadow > 0;
    let plateau_shadow = if verdict == ToolUseTransitionVerdict::Plateau {
        1
    } else {
        0
    };
    let shadow_mass = exposed_shadow
        .saturating_add(regression_debt)
        .saturating_add(plateau_shadow);

    ToolUseMarkovTransition {
        index,
        tool: step.tool.clone(),
        layer,
        from_state: state_for_layer(layer),
        to_state: state_for_verdict(verdict),
        verdict,
        before_score: step.before_score,
        after_score: step.after_score,
        score_gain,
        regression_debt,
        observed_mass: score_gain.saturating_add(step.evidence_bytes),
        shadow_mass,
        residual_shadow: step.residual_shadow,
        symbolic_obligation_count: step.symbolic_obligation_count,
        symbolic_checks_passed: step.symbolic_checks_passed,
        output_checksum: step.output_checksum.clone(),
        gate,
        disciplined,
    }
}

fn compute_metrics(
    transitions: &[ToolUseMarkovTransition],
    authority_boundary: &SemanticAuthorityBoundaryReport,
) -> NeurosymbolicToolMarkovMetrics {
    let transition_count = transitions.len() as u32;
    let disciplined_transition_count = transitions
        .iter()
        .filter(|transition| transition.disciplined)
        .count() as u32;
    let total_synthetic_gnosis_gain = transitions
        .iter()
        .map(|transition| transition.score_gain)
        .sum();
    let transition_shadow_residual: u64 = transitions
        .iter()
        .map(|transition| transition.shadow_mass)
        .sum();
    let total_shadow_residual =
        transition_shadow_residual.saturating_add(authority_boundary.obligation_count as u64);
    let plateau_count = transitions
        .iter()
        .filter(|transition| transition.verdict == ToolUseTransitionVerdict::Plateau)
        .count() as u32;
    let regression_count = transitions
        .iter()
        .filter(|transition| transition.verdict == ToolUseTransitionVerdict::Regression)
        .count() as u32;
    let symbolic_failure_count = transitions
        .iter()
        .filter(|transition| !transition.symbolic_checks_passed)
        .count() as u32;
    let c0_observation_count = transitions
        .iter()
        .filter(|transition| transition.gate.c0_tool_observation)
        .count() as u32;
    let c1_calibration_count = transitions
        .iter()
        .filter(|transition| transition.gate.c1_score_calibration)
        .count() as u32;
    let c2_symbolic_pass_count = transitions
        .iter()
        .filter(|transition| transition.gate.c2_symbolic_validation)
        .count() as u32;
    let c3_framework_audit_count = transitions
        .iter()
        .filter(|transition| transition.gate.c3_framework_audit)
        .count() as u32;
    let all_transitions_disciplined =
        transition_count > 0 && disciplined_transition_count == transition_count;

    let recommended_next_action = recommended_next_action_from_counts(
        all_transitions_disciplined,
        total_shadow_residual,
        plateau_count,
        regression_count,
    );

    NeurosymbolicToolMarkovMetrics {
        transition_count,
        disciplined_transition_count,
        total_synthetic_gnosis_gain,
        total_shadow_residual,
        semantic_claim_count: authority_boundary.claim_count,
        semantic_authority_granted_count: authority_boundary.granted_count,
        semantic_authority_blocked_count: authority_boundary.blocked_count,
        semantic_obligation_count: authority_boundary.obligation_count,
        plateau_count,
        regression_count,
        symbolic_failure_count,
        c0_observation_count,
        c1_calibration_count,
        c2_symbolic_pass_count,
        c3_framework_audit_count,
        all_transitions_disciplined,
        recommended_next_action: recommended_next_action.as_attr().to_string(),
    }
}

fn recommended_next_action(metrics: &NeurosymbolicToolMarkovMetrics) -> ToolUseNextAction {
    recommended_next_action_from_counts(
        metrics.all_transitions_disciplined,
        metrics.total_shadow_residual,
        metrics.plateau_count,
        metrics.regression_count,
    )
}

fn recommended_next_action_from_counts(
    all_transitions_disciplined: bool,
    total_shadow_residual: u64,
    plateau_count: u32,
    regression_count: u32,
) -> ToolUseNextAction {
    if plateau_count > 0 || regression_count > 0 || !all_transitions_disciplined {
        ToolUseNextAction::RepairTooling
    } else if total_shadow_residual > 0 {
        ToolUseNextAction::ArgueObligations
    } else {
        ToolUseNextAction::FoldIntoPrompt
    }
}

fn inferred_layer(
    step: &ToolUseObservation,
    verdict: ToolUseTransitionVerdict,
) -> NeurosymbolicLayer {
    if matches!(
        verdict,
        ToolUseTransitionVerdict::Regression | ToolUseTransitionVerdict::Plateau
    ) {
        NeurosymbolicLayer::C3
    } else if !step.symbolic_checks_passed || step.symbolic_obligation_count > 0 {
        NeurosymbolicLayer::C2
    } else if step.before_score != step.after_score {
        NeurosymbolicLayer::C1
    } else {
        NeurosymbolicLayer::C0
    }
}

fn state_for_layer(layer: NeurosymbolicLayer) -> ToolUseMarkovState {
    match layer {
        NeurosymbolicLayer::C0 => ToolUseMarkovState::ToolCandidate,
        NeurosymbolicLayer::C1 => ToolUseMarkovState::ScoreCalibrated,
        NeurosymbolicLayer::C2 => ToolUseMarkovState::SymbolicChecked,
        NeurosymbolicLayer::C3 => ToolUseMarkovState::FrameworkAudited,
    }
}

fn state_for_verdict(verdict: ToolUseTransitionVerdict) -> ToolUseMarkovState {
    match verdict {
        ToolUseTransitionVerdict::SyntheticGnosisGain => ToolUseMarkovState::SyntheticGnosisGain,
        ToolUseTransitionVerdict::ShadowExposed => ToolUseMarkovState::ShadowResidual,
        ToolUseTransitionVerdict::Plateau | ToolUseTransitionVerdict::Regression => {
            ToolUseMarkovState::UnresolvedRegression
        }
    }
}

fn default_symbolic_checks_passed() -> bool {
    true
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::semantic_authority_boundary::{
        SemanticAuthorityVerdict, SemanticClaimKind, SharedUiEvidenceSurface,
    };

    #[test]
    fn gain_and_shadow_steps_are_disciplined_but_keep_obligations_open() {
        let report = compile_neurosymbolic_tool_markov_report(ToolUseMarkovSpec {
            source_id: "tool-walk".to_string(),
            sequence: 9,
            initial_score: None,
            final_score: None,
            authority_claims: vec![
                SemanticAuthorityClaimSpec {
                    kind: SemanticClaimKind::SpeakerIntent,
                    label: "speaker wants closure".to_string(),
                    evidence_surfaces: vec![SharedUiEvidenceSurface::IntentSignal],
                    confidence_milli: 700,
                    evidence_mass: 2,
                    self_reported: false,
                    user_confirmed: false,
                    externally_validated: false,
                    domain_credentialed: false,
                    contradiction_count: 0,
                },
                SemanticAuthorityClaimSpec {
                    kind: SemanticClaimKind::DiagnosisHypothesis,
                    label: "anxiety".to_string(),
                    evidence_surfaces: vec![SharedUiEvidenceSurface::MentalHealthLayer],
                    confidence_milli: 640,
                    evidence_mass: 3,
                    self_reported: false,
                    user_confirmed: false,
                    externally_validated: false,
                    domain_credentialed: false,
                    contradiction_count: 0,
                },
            ],
            steps: vec![
                ToolUseObservation {
                    tool: "rg".to_string(),
                    layer: None,
                    before_score: 10,
                    after_score: 17,
                    evidence_bytes: 2048,
                    residual_shadow: 0,
                    symbolic_obligation_count: 0,
                    symbolic_checks_passed: true,
                    output_checksum: Some("a0nrg".to_string()),
                },
                ToolUseObservation {
                    tool: "lake build".to_string(),
                    layer: None,
                    before_score: 17,
                    after_score: 17,
                    evidence_bytes: 1024,
                    residual_shadow: 3,
                    symbolic_obligation_count: 1,
                    symbolic_checks_passed: false,
                    output_checksum: Some("a0nlake".to_string()),
                },
            ],
        });

        assert_eq!(report.initial_score, 10);
        assert_eq!(report.final_score, 17);
        assert_eq!(report.metrics.transition_count, 2);
        assert_eq!(report.metrics.disciplined_transition_count, 2);
        assert!(report.metrics.all_transitions_disciplined);
        assert_eq!(report.metrics.total_synthetic_gnosis_gain, 7);
        assert_eq!(report.metrics.total_shadow_residual, 7);
        assert_eq!(report.metrics.semantic_claim_count, 2);
        assert_eq!(report.metrics.semantic_obligation_count, 2);
        assert_eq!(
            report.authority_boundary.claims[1].verdict,
            SemanticAuthorityVerdict::Candidate
        );
        assert_eq!(
            report.recommended_next_action,
            ToolUseNextAction::ArgueObligations
        );
        assert_eq!(
            report.transitions[1].verdict,
            ToolUseTransitionVerdict::ShadowExposed
        );
        assert!(!report.transitions[1].gate.c2_symbolic_validation);

        let frame = tool_markov_report_to_frame(&report).expect("frame");
        assert!(frame.is_neurosymbolic_tool_markov_consciousness());
        assert_eq!(
            frame.attributes.get("recommended_next_action").cloned(),
            Some("argueObligations".to_string())
        );
    }

    #[test]
    fn plateau_without_shadow_requires_tooling_repair() {
        let report = compile_neurosymbolic_tool_markov_report(ToolUseMarkovSpec {
            source_id: "tool-walk".to_string(),
            sequence: 0,
            initial_score: Some(4),
            final_score: Some(4),
            authority_claims: Vec::new(),
            steps: vec![ToolUseObservation {
                tool: "empty-check".to_string(),
                layer: None,
                before_score: 4,
                after_score: 4,
                evidence_bytes: 0,
                residual_shadow: 0,
                symbolic_obligation_count: 0,
                symbolic_checks_passed: true,
                output_checksum: None,
            }],
        });

        assert!(!report.metrics.all_transitions_disciplined);
        assert_eq!(report.metrics.plateau_count, 1);
        assert_eq!(report.metrics.total_shadow_residual, 1);
        assert_eq!(
            report.recommended_next_action,
            ToolUseNextAction::RepairTooling
        );
        assert_eq!(
            report.transitions[0].to_state,
            ToolUseMarkovState::UnresolvedRegression
        );
    }
}
